import React from 'react';

const ScreenSix = ({ achievementGoals, meetingsPerMonth, handleAchievementGoalsChange, handleMeetingsPerMonthChange }) => {
  const meetingOptions = ['1', '2-3', '4'];

  const handleTextareaChange = (event) => {
    handleAchievementGoalsChange(event.target.value);
  };

  const handleRadioChange = (event) => {
    handleMeetingsPerMonthChange(event.target.value);
  };

  return (
    <div>
      <h2>What are you hoping to achieve with our service?</h2>
      <div className="form-group">
        <textarea
          name="achievementGoals"
          value={achievementGoals}
          onChange={handleTextareaChange}
          placeholder="Describe your goals (optional)"
        />
      </div>

      <h2>How many meetings per month would you like to have?</h2>
      <div className="form-group">
        {meetingOptions.map((option, index) => (
          <div key={index} className="radio-group">
            <label>
              <input
                type="radio"
                name="meetingsPerMonth"
                value={option}
                checked={meetingsPerMonth === option}
                onChange={handleRadioChange}
              />
              {option}
            </label>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ScreenSix;
